it('calls /api/workspace/provision before querying posts', async () => {
  const order: string[] = [];
  global.fetch = vi.fn().mockImplementation(async (url) => {
    order.push(url); return new Response(JSON.stringify({ workspaceId: 'xyz' }));
  });
  mockSupabase.from.mockImplementation((tbl) => { order.push(`sb:${tbl}`); return chain; });
  render(<PipelineProvider/>);
  await waitFor(() => expect(order).toEqual(['/api/workspace/provision', 'sb:posts']));
});

it('restores card and shows protected toast when DB rejects approved_scheduled delete', async () => {
  mockSupabase.delete.mockResolvedValue({ error: { message: 'SAFETY BLOCK: ... protected' } });
  const { addToast } = renderHookWithProvider(...);
  await act(() => deleteCard(approvedCard.id));
  expect(cards).toContainEqual(expect.objectContaining({ id: approvedCard.id }));
  expect(addToast).toHaveBeenCalledWith(expect.stringContaining('locked'), 'error');
});

describe('migration 0015', () => {
  beforeAll(applyAllMigrations);
  it('audit_log_v2 row exists after delete', async () => {
    const id = await insertPost({ stage: 'draft' });
    await admin.from('posts').delete().eq('id', id);
    const { data } = await admin.from('audit_log_v2').select().eq('entity_id', id).eq('action', 'post_hard_deleted');
    expect(data).toHaveLength(1);
  });
  it('approved_scheduled rejects delete with P0001', async () => {
    const id = await insertPost({ stage: 'approved_scheduled' });
    const { error } = await admin.from('posts').delete().eq('id', id);
    expect(error.code).toBe('P0001');
  });
  it('stage_changed audit row written on UPDATE', async () => {...});
});

